#include <bits/stdc++.h>
#define gcd(x,y) __gcd(x,y)
#define lcm(x,y) x/__gcd(x,y)*y 
using namespace std;
int A,B=1,n,c,d,e,t;
int main(void){
    scanf("%d",&n);
    for(int i=0;i<n;++i){
    	scanf("%d%d%d",&c,&d,&e);
		t=lcm(B,d),A*=t/B,c*=t/d,B=t,d=t;
        if(e==1)A+=c;else if(e==2)A-=c;
        t=gcd(A,B),A/=t,B/=t;
    }
    if(B==1)printf("%d",A);
    else if((A<0&&B>0)||(A>0&&B<0))printf("-%d/%d",abs(A),abs(B));
    else printf("%d/%d",abs(A),abs(B));
	return false;
}
